// 随机抽取题目函数（确保至少包含2道主观题）
export function getRandomQuestions(role: string, count: number = 45): Question[] {
  const allQuestions = questionBankFull[role] || [];

  if (allQuestions.length <= count) {
    return allQuestions;
  }

  // 分离不同题型
  const shortAnswerQuestions = allQuestions.filter(q => q.type === 5); // 简答题
  const scenarioQuestions = allQuestions.filter(q => q.type === 6); // 情景题
  const otherSubjectiveQuestions = allQuestions.filter(q => q.type === 7); // 其他主观题
  const objectiveQuestions = allQuestions.filter(q => [1, 2, 3, 4].includes(q.type)); // 客观题

  // 确保至少抽取2道简答题和2道情景题
  const shortAnswerCount = Math.min(2, shortAnswerQuestions.length);
  const scenarioCount = Math.min(2, scenarioQuestions.length);
  const totalSubjectiveCount = shortAnswerCount + scenarioCount;

  // 随机抽取简答题
  const shuffledShortAnswer = [...shortAnswerQuestions];
  for (let i = shuffledShortAnswer.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffledShortAnswer[i], shuffledShortAnswer[j]] = [shuffledShortAnswer[j], shuffledShortAnswer[i]];
  }
  const selectedShortAnswer = shuffledShortAnswer.slice(0, shortAnswerCount);

  // 随机抽取情景题
  const shuffledScenario = [...scenarioQuestions];
  for (let i = shuffledScenario.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffledScenario[i], shuffledScenario[j]] = [shuffledScenario[j], shuffledScenario[i]];
  }
  const selectedScenario = shuffledScenario.slice(0, scenarioCount);

  // 如果题库中有其他主观题（type 7），随机抽取1道（可选）
  let selectedOtherSubjective: Question[] = [];
  if (otherSubjectiveQuestions.length > 0 && totalSubjectiveCount < count) {
    const shuffledOther = [...otherSubjectiveQuestions];
    for (let i = shuffledOther.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffledOther[i], shuffledOther[j]] = [shuffledOther[j], shuffledOther[i]];
    }
    selectedOtherSubjective = shuffledOther.slice(0, Math.min(1, otherSubjectiveQuestions.length));
  }

  // 计算还需要抽取的客观题数量
  const totalSubjective = totalSubjectiveCount + selectedOtherSubjective.length;
  const remainingCount = Math.max(0, count - totalSubjective);

  // 随机抽取客观题
  const selectedObjective: Question[] = [];
  if (remainingCount > 0 && objectiveQuestions.length > 0) {
    const shuffledObjective = [...objectiveQuestions];
    for (let i = shuffledObjective.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffledObjective[i], shuffledObjective[j]] = [shuffledObjective[j], shuffledObjective[i]];
    }
    selectedObjective.push(...shuffledObjective.slice(0, remainingCount));
  }

  // 合并并再次打乱顺序
  const result = [...selectedShortAnswer, ...selectedScenario, ...selectedOtherSubjective, ...selectedObjective];
  for (let i = result.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [result[i], result[j]] = [result[j], result[i]];
  }

  return result;
}
